/**
 * @fileoverview MarkdownEditor helpers — pure Markdown parsing, HTML ↔ Markdown
 *               conversion, and other stateless utility functions.
 * @module module/MarkdownEditor/helpers
 */

import razyui from '../../index.js';

// ═══════════════════════════════════════════════════
// Escape / Inline Parsing
// ═══════════════════════════════════════════════════

/**
 * Escape HTML entities.
 * @param {string} text
 * @returns {string}
 */
export function escapeHtml(text) {
    return text
        .replace(/&/g, '&amp;')
        .replace(/</g, '&lt;')
        .replace(/>/g, '&gt;')
        .replace(/"/g, '&quot;');
}

/**
 * Escape a string for use inside an HTML attribute value.
 * @param {string} text
 * @returns {string}
 */
export function escapeAttr(text) {
    return escapeHtml(text).replace(/'/g, '&#39;');
}

/** @typedef {object} MarkdownParseOptions */

export const PARSE_SAFE_DEFAULTS = {
    images: false,
    allowedLinkProtocols: ['https:'],
    linkRel: 'noopener noreferrer',
};

/** Preset option bundles for host apps (e.g. oaao chat bubble). */
export const PARSE_SAFE_PRESETS = {
    'oaao-chat': {
        ...PARSE_SAFE_DEFAULTS,
        linkClass: 'underline fg-[var(--grid-ink)] decoration-[var(--grid-line)]',
        preClass: 'overflow-x-auto rounded-[8px] px-3 py-2 mb-2 text-[0.8125rem] bg-[var(--grid-line)]/12 border-[1px] border-solid border-[var(--grid-line)]',
        codeClass: 'font-mono whitespace-pre',
        inlineCodeClass: 'font-mono text-[0.85em] px-1 py-0.5 rounded-[4px] bg-[var(--grid-line)]/30',
        hrClass: 'oaao-md-hr',
        headingClass: 'oaao-md-heading fw-semibold mb-2 mt-3 text-[clamp(0.9rem,1.02em,1.08rem)] first:mt-0 [line-height:1.35]',
        paragraphClass: 'mb-2 leading-relaxed',
        ulClass: 'list-disc pl-5 mb-2 space-y-1',
        olClass: 'list-decimal pl-5 mb-2 space-y-1',
        tableWrapClass: 'oaao-md-table-wrap',
        tableClass: 'oaao-md-table',
    },
};

const DEFAULT_PARSE_OPTIONS = {
    images: true,
    allowedLinkProtocols: null,
};

/**
 * @param {MarkdownParseOptions | null | undefined} options
 * @param {MarkdownParseOptions} [base]
 * @returns {MarkdownParseOptions}
 */
function mergeParseOptions(options, base = DEFAULT_PARSE_OPTIONS) {
    const preset =
        options && typeof options.preset === 'string' ? PARSE_SAFE_PRESETS[options.preset] : null;
    const merged = { ...base, ...(preset || {}), ...(options || {}) };
    delete merged.preset;
    return merged;
}

/**
 * @param {string} url
 * @param {MarkdownParseOptions} options
 * @returns {boolean}
 */
function isAllowedLinkUrl(url, options) {
    const allowed = options.allowedLinkProtocols;
    try {
        const u = new URL(url, 'https://example.invalid');
        if (!allowed || !Array.isArray(allowed) || allowed.length === 0) {
            return u.protocol === 'http:' || u.protocol === 'https:';
        }
        return allowed.includes(u.protocol);
    } catch {
        return false;
    }
}

/** @param {string | undefined} cls @returns {string} */
function classAttr(cls) {
    return cls ? ` class="${escapeAttr(cls)}"` : '';
}

/**
 * Normalize LaTeX-style math delimiters to markdown forms understood by {@link parse}.
 *
 * Block math requires {@code $$} on its own line; models often emit {@code \[...\]},
 * {@code \(...\)}, or single-line {@code $$…$$}.
 *
 * @param {string} markdown
 * @returns {string}
 */
export function normalizeMarkdownMathDelimiters(markdown) {
    if (!markdown || typeof markdown !== 'string') return '';

    let s = markdown.replace(/\r\n/g, '\n');

    s = s.replace(/\\\[([\s\S]*?)\\\]/g, (_m, inner) => `\n$$\n${String(inner).trim()}\n$$\n`);
    s = s.replace(/\\\(([\s\S]*?)\\\)/g, (_m, inner) => `$${String(inner).trim()}$`);
    s = s.replace(/\$\$([^\n]+?)\$\$/g, (_m, inner) => `\n$$\n${String(inner).trim()}\n$$\n`);

    return s;
}

/**
 * Parse inline Markdown to HTML.
 * Handles: bold, italic, strikethrough, inline code, links, images,
 * highlight (==text==), inline math, and line breaks.
 *
 * @param {string} text — raw inline markdown
 * @param {MarkdownParseOptions} [options]
 * @returns {string} — HTML
 */
export function parseInline(text, options) {
    if (!text) return '';

    const opts = mergeParseOptions(options);

    // Escape HTML (raw tags from untrusted input never pass through)
    text = text.replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;');

    const inlineCodeClass = opts.inlineCodeClass || opts.codeClass || '';

    // Protect code spans first
    const codeSlots = [];
    text = text.replace(/`([^`]+)`/g, (_, code) => {
        codeSlots.push(`<code${classAttr(inlineCodeClass)}>${code}</code>`);
        return `\x00C${codeSlots.length - 1}\x00`;
    });

    // Protect inline math $...$ (but not $$)
    const mathSlots = [];
    text = text.replace(/(?<!\$)\$(?!\$)([^$\n]+?)(?<!\$)\$(?!\$)/g, (_, expr) => {
        mathSlots.push(`<span class="math-inline" data-math="${escapeAttr(expr)}">${expr}</span>`);
        return `\x00M${mathSlots.length - 1}\x00`;
    });

    // Images: ![alt](url "title"?)
    text = text.replace(/!\[([^\]]*)\]\(([^)\s]+)(?:\s+"([^"]*)")?\)/g, (full, alt, url, title) => {
        if (!opts.images) return full;
        return `<img src="${escapeAttr(url)}" alt="${escapeAttr(alt)}"${title ? ` title="${escapeAttr(title)}"` : ''}>`;
    });

    // Links: [text](url "title"?)
    text = text.replace(/\[([^\]]+)\]\(([^)\s]+)(?:\s+"([^"]*)")?\)/g, (full, label, url, title) => {
        if (!isAllowedLinkUrl(url, opts)) return full;
        const rel = opts.linkRel ? ` rel="${escapeAttr(opts.linkRel)}"` : ' rel="noopener"';
        return `<a href="${escapeAttr(url)}"${classAttr(opts.linkClass)}${title ? ` title="${escapeAttr(title)}"` : ''} target="_blank"${rel}>${label}</a>`;
    });

    // Bold + Italic: ***text***
    text = text.replace(/\*{3}(.+?)\*{3}/g, '<strong><em>$1</em></strong>');
    text = text.replace(/_{3}(.+?)_{3}/g, '<strong><em>$1</em></strong>');

    // Bold: **text** or __text__
    text = text.replace(/\*{2}(.+?)\*{2}/g, '<strong>$1</strong>');
    text = text.replace(/__(.+?)__/g, '<strong>$1</strong>');

    // Italic: *text* or _text_
    text = text.replace(/\*(.+?)\*/g, '<em>$1</em>');
    text = text.replace(/(?<!\w)_(.+?)_(?!\w)/g, '<em>$1</em>');

    // Strikethrough: ~~text~~
    text = text.replace(/~~(.+?)~~/g, '<del>$1</del>');

    // Highlight: ==text==
    text = text.replace(/==(.+?)==/g, '<mark>$1</mark>');

    // Line break: trailing double-space
    text = text.replace(/ {2,}$/gm, '<br>');

    // Restore inline math
    text = text.replace(/\x00M(\d+)\x00/g, (_, i) => mathSlots[+i]);

    // Restore code spans
    text = text.replace(/\x00C(\d+)\x00/g, (_, i) => codeSlots[+i]);

    return text;
}

// ═══════════════════════════════════════════════════
// Block-level Parsing
// ═══════════════════════════════════════════════════

/**
 * Render a Markdown table (array of raw lines including header, separator, body).
 * @param {string[]} lines
 * @param {MarkdownParseOptions} [options]
 * @returns {string}
 */
export function renderTable(lines, options) {
    const parseCells = row => row.trim().replace(/^\||\|$/g, '').split('|').map(c => c.trim());
    const rows = lines.filter(l => l.trim()).map(parseCells);
    if (rows.length < 2) return '';

    const opts = mergeParseOptions(options);

    // Alignment from separator row
    const aligns = rows[1].map(c => {
        if (/^:-+:$/.test(c)) return 'center';
        if (/^-+:$/.test(c)) return 'right';
        return '';
    });

    let html = `<table${classAttr(opts.tableClass)}>\n<thead>\n<tr>`;
    rows[0].forEach((c, idx) => {
        const a = aligns[idx] ? ` style="text-align:${aligns[idx]}"` : '';
        html += `<th${a}>${parseInline(c, opts)}</th>`;
    });
    html += '</tr>\n</thead>\n<tbody>';

    for (let r = 2; r < rows.length; r++) {
        html += '\n<tr>';
        (rows[r] || []).forEach((c, idx) => {
            const a = aligns[idx] ? ` style="text-align:${aligns[idx]}"` : '';
            html += `<td${a}>${parseInline(c, opts)}</td>`;
        });
        html += '</tr>';
    }
    html += '\n</tbody>\n</table>';
    return html;
}

/**
 * Convert a Markdown string to an HTML string.
 * Handles: headings, code fences, blockquotes, task lists, unordered &
 * ordered lists, tables, horizontal rules, images, and paragraphs.
 *
 * @param {string} markdown
 * @param {MarkdownParseOptions} [options]
 * @returns {string}
 */
export function parse(markdown, options) {
    if (!markdown) return '';
    const opts = mergeParseOptions(options);
    const lines = normalizeMarkdownMathDelimiters(markdown).split(/\r?\n/);
    const html = [];
    let i = 0;

    while (i < lines.length) {
        const line = lines[i];

        // Empty line — skip
        if (!line.trim()) { i++; continue; }

        // ── Heading ──
        const hm = line.match(/^(#{1,6})\s+(.+)/);
        if (hm) {
            const lvl = hm[1].length;
            html.push(`<h${lvl}${classAttr(opts.headingClass)}>${parseInline(hm[2], opts)}</h${lvl}>`);
            i++; continue;
        }

        // ── Math block $$ ... $$ ──
        if (/^\$\$\s*$/.test(line)) {
            const mathLines = [];
            i++;
            while (i < lines.length && !/^\$\$\s*$/.test(lines[i])) {
                mathLines.push(lines[i]);
                i++;
            }
            if (i < lines.length) i++; // skip closing $$
            const expr = escapeHtml(mathLines.join('\n'));
            html.push(`<div class="math-block" data-math="${escapeAttr(expr)}">${expr}</div>`);
            continue;
        }

        // ── Fenced code block ──
        const cm = line.match(/^`{3,}(\w*)/);
        if (cm) {
            const lang = cm[1];
            const codeLines = [];
            i++;
            while (i < lines.length && !/^`{3,}\s*$/.test(lines[i])) {
                codeLines.push(lines[i]);
                i++;
            }
            if (i < lines.length) i++; // skip closing
            const escaped = escapeHtml(codeLines.join('\n'));
            const langClass = lang ? ` language-${escapeAttr(lang)}` : '';
            const codeCls = opts.codeClass ? `${opts.codeClass}${langClass}` : langClass.trim();
            html.push(
                `<pre${classAttr(opts.preClass)}><code${codeCls ? ` class="${escapeAttr(codeCls)}"` : ''}>${escaped}</code></pre>`,
            );
            continue;
        }

        // ── Horizontal rule ──
        if (/^(\*{3,}|-{3,}|_{3,})\s*$/.test(line)) {
            html.push(`<hr${classAttr(opts.hrClass)}>`);
            i++; continue;
        }

        // ── Blockquote ──
        if (/^>\s?/.test(line)) {
            const qLines = [];
            while (i < lines.length && /^>\s?/.test(lines[i])) {
                qLines.push(lines[i].replace(/^>\s?/, ''));
                i++;
            }
            html.push(`<blockquote>${parse(qLines.join('\n'), opts)}</blockquote>`);
            continue;
        }

        // ── Task list ──
        if (/^[\-*+]\s\[[ xX]\]\s/.test(line)) {
            html.push(`<ul class="task-list${opts.ulClass ? ` ${opts.ulClass}` : ''}">`);
            while (i < lines.length && /^[\-*+]\s\[[ xX]\]\s/.test(lines[i])) {
                const m = lines[i].match(/^[\-*+]\s\[([ xX])\]\s(.+)/);
                if (m) {
                    const checked = m[1] !== ' ';
                    html.push(`<li><input type="checkbox"${checked ? ' checked' : ''} disabled> ${parseInline(m[2], opts)}</li>`);
                }
                i++;
            }
            html.push('</ul>');
            continue;
        }

        // ── Unordered list ──
        if (/^[\-*+]\s/.test(line)) {
            html.push(`<ul${classAttr(opts.ulClass)}>`);
            while (i < lines.length && /^[\-*+]\s/.test(lines[i])) {
                const content = lines[i].replace(/^[\-*+]\s/, '');
                html.push(`<li>${parseInline(content, opts)}</li>`);
                i++;
            }
            html.push('</ul>');
            continue;
        }

        // ── Ordered list ──
        if (/^\d+\.\s/.test(line)) {
            html.push(`<ol${classAttr(opts.olClass)}>`);
            while (i < lines.length && /^\d+\.\s/.test(lines[i])) {
                const content = lines[i].replace(/^\d+\.\s/, '');
                html.push(`<li>${parseInline(content, opts)}</li>`);
                i++;
            }
            html.push('</ol>');
            continue;
        }

        // ── Table ──
        if (/\|/.test(line) && i + 1 < lines.length &&
            /^\|?\s*:?-{3,}:?\s*(\|\s*:?-{3,}:?\s*)+\|?\s*$/.test(lines[i + 1])) {
            const tableLines = [];
            while (i < lines.length && lines[i].includes('|') && lines[i].trim()) {
                tableLines.push(lines[i]);
                i++;
            }
            const tbl = renderTable(tableLines, opts);
            html.push(opts.tableWrapClass ? `<div${classAttr(opts.tableWrapClass)}>${tbl}</div>` : tbl);
            continue;
        }

        // ── Image on its own line ──
        const imgm = line.match(/^!\[([^\]]*)\]\(([^)\s]+)(?:\s+"([^"]*)")?\)\s*$/);
        if (imgm) {
            if (opts.images) {
                html.push(
                    `<figure><img src="${escapeAttr(imgm[2])}" alt="${escapeAttr(imgm[1])}"${imgm[3] ? ` title="${escapeAttr(imgm[3])}"` : ''}></figure>`,
                );
            } else {
                html.push(`<p${classAttr(opts.paragraphClass)}>${escapeHtml(line)}</p>`);
            }
            i++; continue;
        }

        // ── Paragraph ──
        const pLines = [];
        while (i < lines.length && lines[i].trim() &&
               !/^#{1,6}\s/.test(lines[i]) &&
               !/^`{3,}/.test(lines[i]) &&
               !/^\$\$\s*$/.test(lines[i]) &&
               !/^(\*{3,}|-{3,}|_{3,})\s*$/.test(lines[i]) &&
               !/^>\s?/.test(lines[i]) &&
               !/^[\-*+]\s/.test(lines[i]) &&
               !/^\d+\.\s/.test(lines[i])) {
            pLines.push(lines[i]);
            i++;
        }
        if (pLines.length) {
            html.push(`<p${classAttr(opts.paragraphClass)}>${parseInline(pLines.join('\n'), opts)}</p>`);
        }
    }

    return html.join('\n');
}

/**
 * Security-oriented markdown → HTML for untrusted model output.
 *
 * @param {string} markdown
 * @param {MarkdownParseOptions} [options]
 * @returns {string}
 */
export function parseSafe(markdown, options = {}) {
    return parse(markdown, mergeParseOptions(options, PARSE_SAFE_DEFAULTS));
}

// ═══════════════════════════════════════════════════
// Tokenizer (used by BlockEditor)
// ═══════════════════════════════════════════════════

/**
 * Tokenize a Markdown string into an array of block-level tokens.
 * Each token: { type, content, meta? }
 * Used by BlockEditor for importing Markdown into blocks.
 *
 * @param {string} markdown
 * @returns {Array<{type:string, content:string, meta?:object}>}
 */
export function tokenize(markdown) {
    if (!markdown) return [];
    const lines = markdown.split(/\r?\n/);
    const blocks = [];
    let i = 0;

    while (i < lines.length) {
        const line = lines[i];

        if (!line.trim()) { i++; continue; }

        // Heading
        const hm = line.match(/^(#{1,6})\s+(.+)/);
        if (hm) {
            blocks.push({ type: 'heading', content: hm[2].trim(), meta: { level: hm[1].length } });
            i++; continue;
        }

        // Math block
        if (/^\$\$\s*$/.test(line)) {
            const mathLines = [];
            i++;
            while (i < lines.length && !/^\$\$\s*$/.test(lines[i])) {
                mathLines.push(lines[i]);
                i++;
            }
            if (i < lines.length) i++;
            blocks.push({ type: 'math', content: mathLines.join('\n') });
            continue;
        }

        // Code fence
        const cm = line.match(/^`{3,}(\w*)/);
        if (cm) {
            const codeLines = [];
            i++;
            while (i < lines.length && !/^`{3,}\s*$/.test(lines[i])) {
                codeLines.push(lines[i]);
                i++;
            }
            if (i < lines.length) i++;
            blocks.push({ type: 'code', content: codeLines.join('\n'), meta: { language: cm[1] || '' } });
            continue;
        }

        // HR
        if (/^(\*{3,}|-{3,}|_{3,})\s*$/.test(line)) {
            blocks.push({ type: 'divider', content: '' });
            i++; continue;
        }

        // Blockquote
        if (/^>\s?/.test(line)) {
            const qLines = [];
            while (i < lines.length && /^>\s?/.test(lines[i])) {
                qLines.push(lines[i].replace(/^>\s?/, ''));
                i++;
            }
            blocks.push({ type: 'quote', content: qLines.join('\n') });
            continue;
        }

        // Task list item
        if (/^[\-*+]\s\[[ xX]\]\s/.test(line)) {
            while (i < lines.length && /^[\-*+]\s\[[ xX]\]\s/.test(lines[i])) {
                const m = lines[i].match(/^[\-*+]\s\[([ xX])\]\s(.+)/);
                if (m) {
                    blocks.push({ type: 'todo', content: m[2], meta: { checked: m[1] !== ' ' } });
                }
                i++;
            }
            continue;
        }

        // Unordered list
        if (/^[\-*+]\s/.test(line)) {
            while (i < lines.length && /^[\-*+]\s/.test(lines[i])) {
                blocks.push({ type: 'bulleted-list', content: lines[i].replace(/^[\-*+]\s/, '') });
                i++;
            }
            continue;
        }

        // Ordered list
        if (/^\d+\.\s/.test(line)) {
            while (i < lines.length && /^\d+\.\s/.test(lines[i])) {
                blocks.push({ type: 'numbered-list', content: lines[i].replace(/^\d+\.\s/, '') });
                i++;
            }
            continue;
        }

        // Table
        if (/\|/.test(line) && i + 1 < lines.length &&
            /^\|?\s*:?-{3,}:?\s*(\|\s*:?-{3,}:?\s*)+\|?\s*$/.test(lines[i + 1])) {
            const tableLines = [];
            while (i < lines.length && lines[i].includes('|') && lines[i].trim()) {
                tableLines.push(lines[i]);
                i++;
            }
            blocks.push({ type: 'table', content: tableLines.join('\n') });
            continue;
        }

        // Image on own line
        const imgm = line.match(/^!\[([^\]]*)\]\(([^)\s]+)(?:\s+"([^"]*)")?\)\s*$/);
        if (imgm) {
            blocks.push({ type: 'image', content: '', meta: { url: imgm[2], alt: imgm[1], caption: imgm[3] || '' } });
            i++; continue;
        }

        // Paragraph
        const pLines = [];
        while (i < lines.length && lines[i].trim() &&
               !/^#{1,6}\s/.test(lines[i]) &&
               !/^`{3,}/.test(lines[i]) &&
               !/^\$\$\s*$/.test(lines[i]) &&
               !/^(\*{3,}|-{3,}|_{3,})\s*$/.test(lines[i]) &&
               !/^>\s?/.test(lines[i]) &&
               !/^[\-*+]\s/.test(lines[i]) &&
               !/^\d+\.\s/.test(lines[i])) {
            pLines.push(lines[i]);
            i++;
        }
        if (pLines.length) {
            blocks.push({ type: 'paragraph', content: pLines.join('\n') });
        }
    }

    return blocks;
}

// ═══════════════════════════════════════════════════
// HTML → Markdown Converter
// ═══════════════════════════════════════════════════

/**
 * Convert an HTML string back to Markdown.
 * Used by WYSIWYG mode to export contenteditable HTML as Markdown.
 *
 * @param {string} html
 * @returns {string}
 */
export function htmlToMarkdown(html) {
    if (!html) return '';
    const tmp = razyui.el('div', { innerHTML: html })[0];
    return walkNode(tmp).replace(/\n{3,}/g, '\n\n').trim();
}

/**
 * Recursively walk DOM nodes and convert to Markdown.
 * @param {Node} node
 * @returns {string}
 */
export function walkNode(node) {
    let md = '';
    for (const child of node.childNodes) {
        if (child.nodeType === Node.TEXT_NODE) {
            md += child.textContent;
            continue;
        }
        if (child.nodeType !== Node.ELEMENT_NODE) continue;

        const tag = child.tagName.toLowerCase();
        const inner = () => walkNode(child);

        switch (tag) {
            case 'strong': case 'b':
                md += `**${inner()}**`; break;
            case 'em': case 'i':
                md += `*${inner()}*`; break;
            case 'del': case 's':
                md += `~~${inner()}~~`; break;
            case 'code':
                if (razyui(child).parent()[0]?.tagName?.toLowerCase() === 'pre') {
                    md += child.textContent;
                } else {
                    md += `\`${inner()}\``;
                }
                break;
            case 'mark':
                md += `==${inner()}==`; break;
            case 'span':
                if (child.classList.contains('math-inline')) {
                    md += `$${child.getAttribute('data-math') || inner()}$`;
                } else {
                    md += inner();
                }
                break;
            case 'a':
                md += `[${inner()}](${child.getAttribute('href') || ''})`; break;
            case 'img':
                md += `![${child.getAttribute('alt') || ''}](${child.getAttribute('src') || ''})`; break;
            case 'br':
                md += '\n'; break;
            case 'p':
                md += `${inner()}\n\n`; break;
            case 'h1': md += `# ${inner()}\n\n`; break;
            case 'h2': md += `## ${inner()}\n\n`; break;
            case 'h3': md += `### ${inner()}\n\n`; break;
            case 'h4': md += `#### ${inner()}\n\n`; break;
            case 'h5': md += `##### ${inner()}\n\n`; break;
            case 'h6': md += `###### ${inner()}\n\n`; break;
            case 'ul': {
                for (const li of child.children) {
                    if (li.tagName?.toLowerCase() === 'li') {
                        const cb = li.querySelector('input[type="checkbox"]');
                        const liText = walkNode(li).trim();
                        if (cb) {
                            md += `- [${cb.checked ? 'x' : ' '}] ${liText}\n`;
                        } else {
                            md += `- ${liText}\n`;
                        }
                    }
                }
                md += '\n';
                break;
            }
            case 'ol': {
                let n = 1;
                for (const li of child.children) {
                    if (li.tagName?.toLowerCase() === 'li') {
                        md += `${n}. ${walkNode(li).trim()}\n`;
                        n++;
                    }
                }
                md += '\n';
                break;
            }
            case 'blockquote':
                md += inner().trim().split('\n').map(l => `> ${l}`).join('\n') + '\n\n';
                break;
            case 'pre': {
                const codeEl = razyui(child).find('code')[0];
                const lang = codeEl?.className?.match(/language-(\w+)/)?.[1] || '';
                const text = codeEl ? codeEl.textContent : child.textContent;
                md += '```' + lang + '\n' + text + '\n```\n\n';
                break;
            }
            case 'hr':
                md += '---\n\n'; break;
            case 'table':
                md += tableNodeToMd(child) + '\n\n'; break;
            case 'div':
                if (child.classList.contains('math-block')) {
                    md += `$$\n${child.getAttribute('data-math') || child.textContent}\n$$\n\n`;
                } else {
                    md += inner() + '\n';
                }
                break;
            case 'figure':
                md += inner(); break;
            case 'li':
                md += inner(); break;
            default:
                md += inner();
        }
    }
    return md;
}

/**
 * Convert a table DOM node to Markdown table syntax.
 * @param {HTMLTableElement} table
 * @returns {string}
 */
export function tableNodeToMd(table) {
    const rows = [];
    const $table = razyui(table);
    const thead = $table.find('thead')[0];
    const tbody = $table.find('tbody')[0] || table;

    if (thead) {
        const headerRow = razyui(thead).find('tr')[0];
        if (headerRow) {
            const cells = razyui(headerRow).find('th,td').map(c => c.textContent.trim());
            rows.push('| ' + cells.join(' | ') + ' |');
            rows.push('| ' + cells.map(() => '------').join(' | ') + ' |');
        }
    }

    const bodySource = tbody === table ? table : tbody;
    razyui(bodySource).find('tr').each(tr => {
        if (thead && thead.contains(tr)) return;
        const cells = razyui(tr).find('td,th').map(c => c.textContent.trim());
        rows.push('| ' + cells.join(' | ') + ' |');
    });

    return rows.join('\n');
}

