// Misc Utilities
// ═══════════════════════════════════════════════════

/**
 * Simple 32-bit FNV-1a hash of a string → hex.
 * Used for content change detection.
 * @param {string} str
 * @returns {string}
 */
export function contentHash(str) {
    let h = 0x811c9dc5;
    for (let i = 0; i < str.length; i++) {
        h ^= str.charCodeAt(i);
        h = Math.imul(h, 0x01000193);
    }
    return (h >>> 0).toString(16);
}
